async function onResponse(context, request, response) { 
  // TUS ENLACES DE GITHUB (Cámbialos por los tuyos reales)
  const MIS_HUESOS = 'https://cdn.jsdelivr.net/gh/Maxmomaric029/FF-Assets@main/3dr.txt'; 
  const MI_LOBBY = 'https://cdn.jsdelivr.net/gh/Maxmomaric029/FF-Assets@main/lo.txt';

  // INYECCIÓN DE HUESOS (Aimbot/Cabeza)
  if (request.url.includes('/assetindexer')) {
    try {
      const res = await fetch(MIS_HUESOS);
      const data = await res.arrayBuffer();
      response.body = new Uint8Array(data);
      response.statusCode = 200;
      response.headers['Content-Type'] = 'application/octet-stream';
      delete response.headers['Content-Length'];
      console.log('Inyeccion Exitosa - Sin Keys externas');
    } catch (e) { 
      console.log('Error al conectar a tu GitHub');
    }
  }

  / WORDLYY
  if (request.url.includes('/MajorLogin')) {
    try {
      const res = await fetch(MI_LOBBY);
      const text = await res.text();
      response.body = text;
      response.statusCode = 400;
    } catch (e) {
      response.body = 'BIENVENIDO AL IMPERIO DE MAX';
    }
  }

  return response;
}
